'use client';

import React, { useState, useRef, useEffect, useLayoutEffect } from 'react';
import { Task, Connection, Board, Group, TaskFile } from '../../types';
import { TaskCard } from './TaskCard';
import { 
  Plus, Trello, ChevronDown, Check, Pencil, X, MousePointer2, Layers, Spline, Activity, Trash2, FilePlus, Clipboard 
} from 'lucide-react';

interface BoardCanvasProps { 
  tasks: Task[]; 
  connections: Connection[]; 
  onTasksUpdate: (tasks: Task[]) => void; 
  onTaskSelect: (task: Task) => void; 
  onConnectionCreate: (from: string, to: string) => void; 
  onConnectionDelete: (id: string) => void; 
  onConnectionUpdate: (id: string, updates: Partial<Connection>) => void;
  boards: Board[];
  activeBoardId: string;
  onSwitchBoard: (id: string) => void;
  onAddBoard: (name: string) => void;
  onRenameBoard: (id: string, name: string) => void;
  snapToGrid: boolean;
  groups: Group[];
  onGroupsUpdate: (groups: Group[]) => void;
}

export const BoardCanvas: React.FC<BoardCanvasProps> = ({ 
    tasks, connections, onTasksUpdate, onTaskSelect, onConnectionCreate, onConnectionDelete, onConnectionUpdate, boards, activeBoardId, onSwitchBoard, onAddBoard, onRenameBoard, snapToGrid, groups, onGroupsUpdate 
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const boardSelectorRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const taskFileInputRef = useRef<HTMLInputElement>(null);
  const [activeTaskForFile, setActiveTaskForFile] = useState<string | null>(null);

  const mousePosRef = useRef({ x: 0, y: 0 }); // Track mouse position for 'N' shortcut
  const [lines, setLines] = useState<React.ReactElement[]>([]);
  const [svgSize, setSvgSize] = useState({ width: 0, height: 0 });
  const [dragState, setDragState] = useState<{ id: string, startX: number, startY: number, initialTaskX: number, initialTaskY: number } | null>(null);
  const [groupDragState, setGroupDragState] = useState<{ id: string, startX: number, startY: number, initialGroupX: number, initialGroupY: number, containedTaskIds: { id: string, initialX: number, initialY: number }[] } | null>(null);
  const [connectionDraft, setConnectionDraft] = useState<{ fromId: string, startX: number, startY: number, currX: number, currY: number } | null>(null);
  const [activeMenu, setActiveMenu] = useState<{ id: string, x: number, y: number } | null>(null);
  const [backgroundMenu, setBackgroundMenu] = useState<{ x: number, y: number, taskX: number, taskY: number, targetTaskId?: string } | null>(null);
  const [selectionBox, setSelectionBox] = useState<{ startX: number, startY: number, currX: number, currY: number } | null>(null);
  const [selectedTaskIds, setSelectedTaskIds] = useState<Set<string>>(new Set());
  const [editingGroupId, setEditingGroupId] = useState<string | null>(null);
  const [editingGroupTitle, setEditingGroupTitle] = useState('');
  const [showBoardMenu, setShowBoardMenu] = useState(false);
  const [isCreatingBoard, setIsCreatingBoard] = useState(false);
  const [newBoardName, setNewBoardName] = useState('');
  const [editingBoardId, setEditingBoardId] = useState<string | null>(null);
  const [editBoardName, setEditBoardName] = useState('');

  useEffect(() => {
      if (!showBoardMenu) {
          setIsCreatingBoard(false);
          setNewBoardName('');
          setEditingBoardId(null);
      }
  }, [showBoardMenu]);

  const updateConnections = () => {
      if (!containerRef.current) return;
      const container = containerRef.current;
      const containerRect = container.getBoundingClientRect();
      const newLines: React.ReactElement[] = [];
      setSvgSize({ width: container.scrollWidth, height: container.scrollHeight });

      connections.forEach((conn) => {
          const fromEl = document.getElementById(`task-${conn.from}`);
          const toEl = document.getElementById(`task-${conn.to}`);
          if (fromEl && toEl) {
              const fromRect = fromEl.getBoundingClientRect();
              const toRect = toEl.getBoundingClientRect();
              const startX = fromRect.right - containerRect.left + container.scrollLeft;
              const startY = fromRect.top - containerRect.top + fromRect.height / 2 + container.scrollTop;
              const endX = toRect.left - containerRect.left + container.scrollLeft;
              const endY = toRect.top - containerRect.top + toRect.height / 2 + container.scrollTop;
              const dist = Math.abs(endX - startX);
              let pathString = "";
              if (conn.shape === 'straight') { pathString = `M ${startX} ${startY} L ${endX} ${endY}`; } else { const cp1x = startX + dist * 0.5; const cp1y = startY; const cp2x = endX - dist * 0.5; const cp2y = endY; pathString = `M ${startX} ${startY} C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${endX} ${endY}`; }
              const isSelected = activeMenu?.id === conn.id;
              newLines.push(
                  <g key={conn.id} className="group/line">
                      <path d={pathString} fill="none" stroke="transparent" strokeWidth="20" strokeLinecap="round" className="cursor-pointer pointer-events-auto" onDoubleClick={(e) => { e.stopPropagation(); const rect = container.getBoundingClientRect(); setActiveMenu({ id: conn.id, x: e.clientX - rect.left + container.scrollLeft, y: e.clientY - rect.top + container.scrollTop }); setBackgroundMenu(null); }} onContextMenu={(e) => { e.preventDefault(); e.stopPropagation(); const rect = container.getBoundingClientRect(); setActiveMenu({ id: conn.id, x: e.clientX - rect.left + container.scrollLeft, y: e.clientY - rect.top + container.scrollTop }); setBackgroundMenu(null); }} />
                      <path d={pathString} fill="none" stroke={isSelected ? "#E879F9" : "rgba(255,255,255,0.6)"} strokeWidth="3" strokeLinecap="round" strokeDasharray={conn.style === 'dashed' ? "8,4" : "none"} className={`transition-colors pointer-events-none group-hover/line:stroke-domo-primary ${isSelected ? 'stroke-domo-highlight' : ''}`} />
                       <circle cx={startX} cy={startY} r="4" fill="rgba(255,255,255,0.9)" className="pointer-events-none"/>
                       <path d={`M ${endX} ${endY} L ${endX - 10} ${endY - 5} L ${endX - 10} ${endY + 5} Z`} fill="rgba(255,255,255,0.9)" className="pointer-events-none" />
                  </g>
              );
          }
      });
      if (connectionDraft) {
          const dist = Math.abs(connectionDraft.currX - connectionDraft.startX);
          const cp1x = connectionDraft.startX + dist * 0.5;
          const cp1y = connectionDraft.startY;
          const cp2x = connectionDraft.currX - dist * 0.5;
          const cp2y = connectionDraft.currY;
          const pathString = `M ${connectionDraft.startX} ${connectionDraft.startY} C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${connectionDraft.currX} ${connectionDraft.currY}`;
          newLines.push(<g key="draft"><path d={pathString} fill="none" stroke="rgba(255, 255, 255, 0.8)" strokeWidth="2" strokeDasharray="5,5" strokeLinecap="round" /><circle cx={connectionDraft.currX} cy={connectionDraft.currY} r="3" fill="white" /></g>);
      }
      setLines(newLines);
  };

  useLayoutEffect(() => {
      updateConnections();
      const handleResize = () => updateConnections();
      window.addEventListener('resize', handleResize);
      let animationFrameId: number;
      const loop = () => { updateConnections(); animationFrameId = requestAnimationFrame(loop); };
      loop();
      return () => { window.removeEventListener('resize', handleResize); cancelAnimationFrame(animationFrameId); };
  }, [tasks, connections, connectionDraft, activeMenu]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        const key = e.key.toLowerCase();

        if (key === 'c' && selectedTaskIds.size > 0) {
            e.preventDefault();
            const selectedTasks = tasks.filter(t => selectedTaskIds.has(t.id));
            if (selectedTasks.length === 0) return;
            let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
            selectedTasks.forEach(t => {
                const tx = t.x || 0; const ty = t.y || 0; const tWidth = 280; const tHeight = 200; 
                minX = Math.min(minX, tx); minY = Math.min(minY, ty); maxX = Math.max(maxX, tx + tWidth); maxY = Math.max(maxY, ty + tHeight);
            });
            const padding = 40;
            const newGroup: Group = { id: `group-${Date.now()}`, title: 'Group', x: minX - padding, y: minY - padding, width: maxX - minX + (padding * 2), height: maxY - minY + (padding * 2), boardId: activeBoardId };
            onGroupsUpdate([...groups, newGroup]); setSelectedTaskIds(new Set()); 
        }

        // New 'N' shortcut to create task at mouse position
        if (key === 'n') {
            e.preventDefault();
            const newTask: Task = { 
                id: Date.now().toString(), 
                title: "새로운 카드", 
                status: "todo", 
                x: mousePosRef.current.x - 140, // Center the new card on cursor (card width approx 280)
                y: mousePosRef.current.y - 40,  // Center height approx
                tags: [], 
                boardId: activeBoardId 
            };
            onTasksUpdate([...tasks, newTask]);
            onTaskSelect(newTask);
        }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedTaskIds, tasks, activeBoardId, onTasksUpdate, onTaskSelect, groups, onGroupsUpdate]);

  useEffect(() => {
      const handleClickOutside = (e: MouseEvent) => { 
        setActiveMenu(null); 
        setBackgroundMenu(null); 
        if (editingGroupId) { setEditingGroupId(null); } 

        if (boardSelectorRef.current && !boardSelectorRef.current.contains(e.target as Node)) {
             setShowBoardMenu(false);
        }
      };
      window.addEventListener('mousedown', handleClickOutside);
      return () => window.removeEventListener('mousedown', handleClickOutside);
  }, [editingGroupId]);

  const handlePointerDown = (e: React.PointerEvent, task?: Task, group?: Group) => {
      if (e.button === 2) return;
      if (!containerRef.current) return;
      const container = containerRef.current;
      const rect = container.getBoundingClientRect();
      const x = e.clientX - rect.left + container.scrollLeft;
      const y = e.clientY - rect.top + container.scrollTop;

      if (e.ctrlKey) { e.preventDefault(); e.stopPropagation(); setSelectionBox({ startX: x, startY: y, currX: x, currY: y }); return; }

      if (group) {
        e.stopPropagation(); (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
        const contained = tasks.filter(t => { const tx = t.x || 0; const ty = t.y || 0; return tx >= group.x && tx <= group.x + group.width && ty >= group.y && ty <= group.y + group.height; }).map(t => ({ id: t.id, initialX: t.x || 0, initialY: t.y || 0 }));
        setGroupDragState({ id: group.id, startX: e.clientX, startY: e.clientY, initialGroupX: group.x, initialGroupY: group.y, containedTaskIds: contained });
        setActiveMenu(null); setBackgroundMenu(null); return;
      }
      if (task) {
          (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
          setDragState({ id: task.id, startX: e.clientX, startY: e.clientY, initialTaskX: task.x || 0, initialTaskY: task.y || 0 });
          e.stopPropagation(); setActiveMenu(null); setBackgroundMenu(null);
      }

      // If clicking on empty canvas, verify we aren't clicking a menu
      // The menus handle stopPropagation, so if we reach here, close them.
      setActiveMenu(null); 
      setBackgroundMenu(null);
  };

  const handleConnectStart = (taskId: string, e: React.PointerEvent) => {
      if (!containerRef.current) return;
      const container = containerRef.current;
      const rect = container.getBoundingClientRect();
      const x = e.clientX - rect.left + container.scrollLeft;
      const y = e.clientY - rect.top + container.scrollTop;
      setConnectionDraft({ fromId: taskId, startX: x, startY: y, currX: x, currY: y });
      setActiveMenu(null); setBackgroundMenu(null);
  };

  const handleConnectEnd = (targetId: string) => { if (connectionDraft && connectionDraft.fromId !== targetId) { onConnectionCreate(connectionDraft.fromId, targetId); } setConnectionDraft(null); };

  const handlePointerMove = (e: React.PointerEvent) => {
      if (!containerRef.current) return;
      const container = containerRef.current;
      const rect = container.getBoundingClientRect();
      const x = e.clientX - rect.left + container.scrollLeft;
      const y = e.clientY - rect.top + container.scrollTop;

      // Always track mouse position for 'N' shortcut
      mousePosRef.current = { x, y };

      if (selectionBox) {
          setSelectionBox(prev => prev ? { ...prev, currX: x, currY: y } : null);
          const startX = Math.min(selectionBox.startX, x); const startY = Math.min(selectionBox.startY, y); const endX = Math.max(selectionBox.startX, x); const endY = Math.max(selectionBox.startY, y);
          const newSelectedIds = new Set<string>();
          tasks.forEach(t => { const tx = t.x || 0; const ty = t.y || 0; const tw = 280; const th = 100; if (tx < endX && tx + tw > startX && ty < endY && ty + th > startY) { newSelectedIds.add(t.id); } });
          setSelectedTaskIds(newSelectedIds);
      } else if (groupDragState) {
          const deltaX = e.clientX - groupDragState.startX; const deltaY = e.clientY - groupDragState.startY;
          let newGroupX = groupDragState.initialGroupX + deltaX;
          let newGroupY = groupDragState.initialGroupY + deltaY;

          if (snapToGrid) {
            newGroupX = Math.round(newGroupX / 20) * 20;
            newGroupY = Math.round(newGroupY / 20) * 20;
          }

          onGroupsUpdate(groups.map(g => g.id === groupDragState.id ? { ...g, x: newGroupX, y: newGroupY } : g));

          if (groupDragState.containedTaskIds.length > 0) { 
            const effectiveDeltaX = newGroupX - groupDragState.initialGroupX;
            const effectiveDeltaY = newGroupY - groupDragState.initialGroupY;

            const updatedTasks = tasks.map(t => { 
                const c = groupDragState.containedTaskIds.find(x => x.id === t.id); 
                if (c) { return { ...t, x: c.initialX + effectiveDeltaX, y: c.initialY + effectiveDeltaY }; } 
                return t; 
            }); 
            onTasksUpdate(updatedTasks); 
          }
      } else if (dragState) {
          const deltaX = e.clientX - dragState.startX; const deltaY = e.clientY - dragState.startY;
          let newX = dragState.initialTaskX + deltaX;
          let newY = dragState.initialTaskY + deltaY;

          if (snapToGrid) {
            newX = Math.round(newX / 20) * 20;
            newY = Math.round(newY / 20) * 20;
          }

          const updatedTasks = tasks.map(t => t.id === dragState.id ? { ...t, x: newX, y: newY } : t); 
          onTasksUpdate(updatedTasks);
      } else if (connectionDraft) {
          setConnectionDraft(prev => prev ? { ...prev, currX: x, currY: y } : null);
      }
  };

  const handlePointerUp = (e: React.PointerEvent) => { if (selectionBox) setSelectionBox(null); if(dragState) setDragState(null); if(groupDragState) setGroupDragState(null); if(connectionDraft) setConnectionDraft(null); };

  const handleBackgroundContextMenu = (e: React.MouseEvent) => {
    e.preventDefault(); 
    if (!containerRef.current) return;
    const container = containerRef.current; 
    const rect = container.getBoundingClientRect(); 
    const x = e.clientX - rect.left + container.scrollLeft; 
    const y = e.clientY - rect.top + container.scrollTop;

    // Check if clicked on a task
    const taskEl = (e.target as HTMLElement).closest('[id^="task-"]');
    const targetTaskId = taskEl ? taskEl.id.replace('task-', '') : undefined;

    // Clear other interactions
    setActiveMenu(null); 

    if (targetTaskId) {
        setSelectedTaskIds(new Set([targetTaskId]));
    } else {
        setSelectedTaskIds(new Set()); 
    }

    // Set menu position
    setBackgroundMenu({ x, y, taskX: x - 140, taskY: y - 70, targetTaskId });
  };

  const handleCreateTaskFromMenu = () => {
    if (!backgroundMenu) return;
    const newTask: Task = { 
        id: Date.now().toString(), 
        title: "새로운 카드", 
        status: "todo", 
        x: backgroundMenu.taskX, 
        y: backgroundMenu.taskY, 
        tags: [], 
        boardId: activeBoardId 
    };
    onTasksUpdate([...tasks, newTask]); 
    onTaskSelect(newTask); 
    setBackgroundMenu(null);
  };

  const getConnectionById = (id: string) => connections.find(c => c.id === id);

  const handleGlobalFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const fileList = Array.from(e.target.files) as File[];
        if (!containerRef.current) return;
        const container = containerRef.current;

        const taskFiles: TaskFile[] = fileList.map(f => ({
            name: f.name,
            url: URL.createObjectURL(f),
            size: f.size,
            type: f.type
        }));

        const isFolder = taskFiles.length > 1;

        const newTask: Task = {
            id: Date.now().toString(),
            title: isFolder ? "새 폴더" : taskFiles[0].name,
            status: 'todo',
            description: isFolder ? `${taskFiles.length}개의 파일` : `Type: ${taskFiles[0].type}\nSize: ${(taskFiles[0].size / 1024).toFixed(1)} KB`,
            x: container.scrollLeft + (container.clientWidth / 2) - 50,
            y: container.scrollTop + (container.clientHeight / 2) - 50,
            tags: [],
            boardId: activeBoardId,
            taskType: 2, // File type
            files: taskFiles
        };
        onTasksUpdate([...tasks, newTask]);
        onTaskSelect(newTask);
        e.target.value = ''; // Reset input
    }
  };

  const handleTaskFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (activeTaskForFile && e.target.files && e.target.files.length > 0) {
          const fileList = Array.from(e.target.files) as File[];
          const newFiles: TaskFile[] = fileList.map(f => ({
              name: f.name,
              url: URL.createObjectURL(f),
              size: f.size,
              type: f.type
          }));

          const task = tasks.find(t => t.id === activeTaskForFile);
          if (task) {
              const updatedTask: Task = {
                  ...task,
                  files: [...(task.files || []), ...newFiles],
                  taskType: task.taskType !== 2 ? 2 : task.taskType // Switch to file/folder type if not already
              };
              onTasksUpdate(tasks.map(t => t.id === activeTaskForFile ? updatedTask : t));
          }
          setActiveTaskForFile(null);
          e.target.value = '';
      }
  };

  return (
    <div className="flex flex-col h-full bg-gradient-to-br from-[#5B4480] to-[#9D546C] rounded-xl overflow-hidden shadow-xl border border-white/5 relative">
      <div className="p-4 border-b border-white/10 flex justify-between items-center bg-black/10 backdrop-blur-md relative z-20">
        <div className="relative" ref={boardSelectorRef}>
            <button 
                onClick={(e) => { e.stopPropagation(); setShowBoardMenu(!showBoardMenu); }}
                className="flex items-center gap-2 hover:bg-white/10 px-2 py-1 rounded-lg transition-colors group"
            >
                <div className="bg-white/10 p-1 rounded group-hover:bg-white/20 transition-colors">
                    <Trello size={18} className="text-white" />
                </div>
                <h2 className="font-semibold text-white text-lg tracking-tight">{boards.find(b => b.id === activeBoardId)?.title}</h2>
                <ChevronDown size={16} className={`text-white/70 transition-transform duration-200 ${showBoardMenu ? 'rotate-180' : ''}`} />
            </button>

            {showBoardMenu && (
                <div className="absolute top-full left-0 mt-2 w-64 bg-[#2c333a] border border-gray-700/50 rounded-xl shadow-2xl overflow-hidden z-50 animate-in fade-in zoom-in-95 duration-100">
                    <div className="p-2 border-b border-gray-700/50">
                        <p className="text-xs font-bold text-gray-500 px-3 py-2 uppercase tracking-wider">내 보드</p>
                        {boards.map(board => (
                            <div key={board.id} className="group relative">
                                {editingBoardId === board.id ? (
                                    <div className="px-3 py-2 flex items-center gap-2">
                                        <input 
                                            autoFocus
                                            className="bg-transparent border border-domo-primary rounded px-1 text-sm text-white w-full outline-none"
                                            value={editBoardName}
                                            onChange={(e) => setEditBoardName(e.target.value)}
                                            onClick={(e) => e.stopPropagation()}
                                            onKeyDown={(e) => {
                                                if (e.key === 'Enter') {
                                                    if (editBoardName.trim()) onRenameBoard(board.id, editBoardName.trim());
                                                    setEditingBoardId(null);
                                                }
                                            }}
                                        />
                                        <button onClick={(e) => { e.stopPropagation(); if(editBoardName.trim()) onRenameBoard(board.id, editBoardName.trim()); setEditingBoardId(null); }}><Check size={14} className="text-green-400"/></button>
                                        <button onClick={(e) => { e.stopPropagation(); setEditingBoardId(null); }}><X size={14} className="text-red-400"/></button>
                                    </div>
                                ) : (
                                    <button
                                        onClick={(e) => { e.stopPropagation(); onSwitchBoard(board.id); setShowBoardMenu(false); }}
                                        className="w-full flex items-center justify-between px-3 py-2.5 hover:bg-white/5 rounded-lg text-sm text-gray-200 transition-colors group"
                                    >
                                        <span className="font-medium truncate max-w-[140px]">{board.title}</span>
                                        <div className="flex items-center gap-2">
                                             {board.id === activeBoardId && <Check size={16} className="text-domo-highlight" />}
                                             <div 
                                                className="p-1 hover:bg-white/10 rounded opacity-0 group-hover:opacity-100 transition-opacity"
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setEditingBoardId(board.id);
                                                    setEditBoardName(board.title);
                                                }}
                                             >
                                                <Pencil size={12} className="text-gray-400 hover:text-white" />
                                             </div>
                                        </div>
                                    </button>
                                )}
                            </div>
                        ))}
                    </div>
                    <div className="p-2">
                        {isCreatingBoard ? (
                             <div className="p-2 bg-black/20 rounded-lg">
                                <input 
                                    autoFocus
                                    type="text"
                                    className="w-full bg-[#1E212B] text-white text-sm rounded px-2 py-1.5 border border-gray-600 focus:border-domo-primary outline-none mb-2"
                                    placeholder="보드 이름 입력"
                                    value={newBoardName}
                                    onChange={(e) => setNewBoardName(e.target.value)}
                                    onClick={(e) => e.stopPropagation()}
                                    onKeyDown={(e) => {
                                        e.stopPropagation();
                                        if (e.key === 'Enter' && newBoardName.trim()) {
                                            onAddBoard(newBoardName.trim());
                                            setShowBoardMenu(false);
                                        }
                                    }}
                                />
                                <div className="flex gap-2 justify-end">
                                     <button
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            setIsCreatingBoard(false);
                                        }}
                                        className="px-3 py-1.5 text-xs text-gray-400 hover:text-white"
                                     >
                                        취소
                                     </button>
                                     <button
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            if (newBoardName.trim()) {
                                                onAddBoard(newBoardName.trim());
                                                setShowBoardMenu(false);
                                            }
                                        }}
                                        className="px-3 py-1.5 bg-domo-primary text-white text-xs rounded hover:bg-domo-primary-hover font-medium"
                                     >
                                        만들기
                                     </button>
                                </div>
                             </div>
                        ) : (
                            <button 
                                onClick={(e) => { 
                                    e.stopPropagation(); 
                                    setIsCreatingBoard(true);
                                }}
                                className="w-full flex items-center gap-2 px-3 py-2.5 hover:bg-white/5 rounded-lg text-sm text-gray-400 hover:text-white transition-all font-medium"
                            >
                                <Plus size={16} />
                                <span>새 보드 만들기</span>
                            </button>
                        )}
                    </div>
                </div>
            )}
        </div>
        <div className="text-xs text-white/70 flex items-center gap-4 mr-14"><div className="flex items-center gap-1"><span className="bg-white/10 px-1.5 rounded">Ctrl</span><span>+ Drag to Select</span></div><div className="flex items-center gap-1"><span className="bg-white/10 px-1.5 rounded">C</span><span>to Group</span></div><div className="flex items-center gap-2 border-l border-white/10 pl-4"><MousePointer2 size={12} /><span>우클릭 / 'N' 키로 생성</span></div></div>
      </div>
      <div ref={containerRef} className="flex-1 overflow-auto relative custom-scrollbar w-full h-full bg-[radial-gradient(rgba(255,255,255,0.1)_1px,transparent_1px)] bg-[length:20px_20px]" onContextMenu={handleBackgroundContextMenu} onPointerDown={(e) => handlePointerDown(e)} onPointerMove={handlePointerMove} onPointerUp={handlePointerUp} onPointerLeave={handlePointerUp}>
        <svg className="absolute top-0 left-0 pointer-events-none z-0" style={{ width: Math.max(svgSize.width, 2000), height: Math.max(svgSize.height, 2000) }}>{lines}</svg>
        {groups.map(group => (
            <div key={group.id} className="absolute border-2 border-dashed border-white/20 bg-white/5 rounded-3xl transition-all duration-300 group/item hover:border-white/40 hover:bg-white/10" style={{ left: group.x, top: group.y, width: group.width, height: group.height, cursor: groupDragState ? 'grabbing' : 'grab', pointerEvents: 'auto' }} onPointerDown={(e) => handlePointerDown(e, undefined, group)}>
                <div className="absolute -top-8 left-0 min-w-[100px] pointer-events-auto" onPointerDown={(e) => e.stopPropagation()} onClick={(e) => e.stopPropagation()}>
                     {editingGroupId === group.id ? (
                         <div className="flex items-center gap-2 bg-gray-900/90 p-1.5 rounded-md shadow-lg border border-white/10">
                            <Layers size={14} className="text-domo-primary" /><input autoFocus type="text" value={editingGroupTitle} onChange={(e) => setEditingGroupTitle(e.target.value)} onBlur={() => { if (editingGroupTitle.trim()) { onGroupsUpdate(groups.map(g => g.id === group.id ? { ...g, title: editingGroupTitle } : g)); } setEditingGroupId(null); }} onKeyDown={(e) => { if (e.key === 'Enter') { if (editingGroupTitle.trim()) { onGroupsUpdate(groups.map(g => g.id === group.id ? { ...g, title: editingGroupTitle } : g)); } setEditingGroupId(null); } }} className="bg-transparent text-sm text-white outline-none w-32 font-bold" />
                         </div>
                     ) : (
                        <div className="flex items-center gap-2 text-white/50 hover:text-white font-bold text-sm cursor-text px-2 py-1 hover:bg-white/5 rounded transition-colors" onClick={() => { setEditingGroupId(group.id); setEditingGroupTitle(group.title); }}><Layers size={14} />{group.title}</div>
                     )}
                </div>
            </div>
        ))}
        {tasks.map(task => (
            <TaskCard 
                key={task.id} 
                task={task} 
                variant="sticky" 
                style={{ position: 'absolute', left: task.x || 0, top: task.y || 0 }} 
                isSelected={selectedTaskIds.has(task.id)} 
                onPointerDown={(e) => handlePointerDown(e, task)} 
                onClick={() => onTaskSelect(task)} 
                onConnectStart={handleConnectStart} 
                onConnectEnd={handleConnectEnd} 
                onAttachFile={(taskId) => { setActiveTaskForFile(taskId); taskFileInputRef.current?.click(); }}
            />
        ))}
        {selectionBox && (<div className="absolute border-2 border-blue-500 bg-blue-500/20 rounded z-50 pointer-events-none" style={{ left: Math.min(selectionBox.startX, selectionBox.currX), top: Math.min(selectionBox.startY, selectionBox.currY), width: Math.abs(selectionBox.currX - selectionBox.startX), height: Math.abs(selectionBox.currY - selectionBox.startY) }} />)}
        {activeMenu && (
            <div className="absolute z-50 bg-white dark:bg-[#2c333a] rounded-lg shadow-xl border border-gray-200 dark:border-gray-700 p-1 flex flex-col gap-1 min-w-[120px] animate-in fade-in zoom-in-95 duration-100" style={{ left: activeMenu.x, top: activeMenu.y }} onClick={(e) => e.stopPropagation()} onPointerDown={(e) => e.stopPropagation()} onMouseDown={(e) => e.stopPropagation()}>
                <button onClick={() => { const conn = getConnectionById(activeMenu.id); if (conn) onConnectionUpdate(activeMenu.id, { shape: conn.shape === 'straight' ? 'bezier' : 'straight' }); setActiveMenu(null); }} className="flex items-center gap-2 px-3 py-2 text-xs hover:bg-gray-100 dark:hover:bg-gray-700 rounded text-gray-700 dark:text-gray-200"><Spline size={14} /><span>{getConnectionById(activeMenu.id)?.shape === 'straight' ? '곡선으로 변경' : '직선으로 변경'}</span></button>
                <button onClick={() => { const conn = getConnectionById(activeMenu.id); if (conn) onConnectionUpdate(activeMenu.id, { style: conn.style === 'dashed' ? 'solid' : 'dashed' }); setActiveMenu(null); }} className="flex items-center gap-2 px-3 py-2 text-xs hover:bg-gray-100 dark:hover:bg-gray-700 rounded text-gray-700 dark:text-gray-200"><Activity size={14} /><span>{getConnectionById(activeMenu.id)?.style === 'dashed' ? '실선으로 변경' : '점선으로 변경'}</span></button>
                <div className="h-[1px] bg-gray-200 dark:bg-gray-700 my-0.5"></div>
                <button onClick={() => { onConnectionDelete(activeMenu.id); setActiveMenu(null); }} className="flex items-center gap-2 px-3 py-2 text-xs hover:bg-red-50 dark:hover:bg-red-900/30 text-red-600 dark:text-red-400 rounded"><Trash2 size={14} /><span>삭제</span></button>
            </div>
        )}
        {backgroundMenu && (
            <div 
                className="absolute z-[100] bg-white dark:bg-[#2c333a] rounded-lg shadow-xl border border-gray-200 dark:border-gray-700 p-1 flex flex-col gap-1 min-w-[160px] animate-in fade-in zoom-in-95 duration-100" 
                style={{ left: backgroundMenu.x, top: backgroundMenu.y }} 
                onClick={(e) => e.stopPropagation()} 
                onPointerDown={(e) => e.stopPropagation()}
                onMouseDown={(e) => e.stopPropagation()} 
                onContextMenu={(e) => { e.preventDefault(); e.stopPropagation(); }}
            >
                <button 
                    onClick={handleCreateTaskFromMenu} 
                    className="flex items-center gap-2 px-3 py-2 text-xs hover:bg-gray-100 dark:hover:bg-gray-700 rounded text-gray-700 dark:text-gray-200 w-full text-left"
                >
                    <FilePlus size={14} /><span>새로운 카드 추가</span>
                </button>
                {backgroundMenu.targetTaskId && (
                    <button 
                        onClick={() => { 
                             onTasksUpdate(tasks.filter(t => t.id !== backgroundMenu.targetTaskId)); 
                             setBackgroundMenu(null); 
                        }} 
                        className="flex items-center gap-2 px-3 py-2 text-xs hover:bg-red-50 dark:hover:bg-red-900/30 text-red-600 dark:text-red-400 rounded w-full text-left"
                    >
                        <Trash2 size={14} /><span>카드 제거</span>
                    </button>
                )}
                <button disabled className="flex items-center gap-2 px-3 py-2 text-xs hover:bg-gray-100 dark:hover:bg-gray-700 rounded text-gray-400 cursor-not-allowed w-full text-left">
                    <Clipboard size={14} /><span>붙여넣기</span>
                </button>
            </div>
        )}
      </div>

      <button 
        onClick={() => fileInputRef.current?.click()}
        className="absolute bottom-8 right-8 w-14 h-14 bg-domo-primary hover:bg-domo-primary-hover text-white rounded-full shadow-[0_8px_30px_rgb(0,0,0,0.3)] hover:shadow-[0_8px_35px_rgb(0,0,0,0.4)] transition-all duration-300 hover:scale-110 active:scale-95 flex items-center justify-center z-40 group"
      >
        <Plus size={32} strokeWidth={3} className="group-hover:rotate-90 transition-transform duration-300" />
      </button>

      {/* Global File Input */}
      <input type="file" multiple ref={fileInputRef} className="hidden" onChange={handleGlobalFileChange} />

      {/* Specific Task File Input */}
      <input type="file" multiple ref={taskFileInputRef} className="hidden" onChange={handleTaskFileChange} />
    </div>
  );
};

'use client';

import React, { useState } from 'react';
import { Task } from '../../types';
import { getStickyStyle, getContrastColor } from '../../lib/canvasUtils';
import { 
  FolderOpen, FileText, Download, Folder, Clock, AlignLeft, Paperclip, MoreHorizontal, ChevronRight 
} from 'lucide-react';

interface TaskCardProps { 
  task: Task; 
  onClick: () => void; 
  onMove?: () => void; 
  transparent?: boolean;
  variant?: 'default' | 'sticky';
  style?: React.CSSProperties;
  isSelected?: boolean;
  onPointerDown?: (e: React.PointerEvent) => void;
  onConnectStart?: (taskId: string, e: React.PointerEvent) => void;
  onConnectEnd?: (taskId: string) => void;
  onAttachFile?: (taskId: string) => void;
}

export const TaskCard: React.FC<TaskCardProps> = ({ 
  task, onClick, onMove, transparent, variant = 'default', style, isSelected, onPointerDown, onConnectStart, onConnectEnd, onAttachFile 
}) => {
  const [isExpanded, setIsExpanded] = useState(false);

  const handleDragStart = (e: React.DragEvent) => {
    if (variant !== 'sticky') {
        e.dataTransfer.setData('taskId', task.id);
        e.dataTransfer.effectAllowed = 'move';
    } else {
        e.preventDefault();
    }
  };

  const handleClick = (e: React.MouseEvent) => {
    const isFolder = task.taskType === 2 && task.files && task.files.length > 1;

    if (variant === 'sticky' && (task.taskType !== 2 || isFolder)) {
      e.stopPropagation();
      setIsExpanded(!isExpanded);
    } else {
      onClick();
    }
  };

  const handleDoubleClick = (e: React.MouseEvent) => {
    if (variant === 'sticky') {
      e.stopPropagation();
      onClick(); 
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    const isFolder = task.taskType === 2 && task.files && task.files.length > 1;
    if (e.key === 'Enter') {
        e.preventDefault();
        e.stopPropagation();
        onClick(); 
    } else if (e.key === ' ' && variant === 'sticky' && (task.taskType !== 2 || isFolder)) {
        e.preventDefault();
        e.stopPropagation();
        setIsExpanded(!isExpanded); 
    }
  };

  // --- FILE / FOLDER TYPE RENDER (TaskType === 2) ---
  if (task.taskType === 2 && variant === 'sticky') {
    const isFolder = task.files && task.files.length > 1;

    // EXPANDED FOLDER VIEW
    if (isFolder && isExpanded) {
        return (
            <div 
              id={`task-${task.id}`}
              draggable
              onDragStart={handleDragStart}
              onPointerDown={onPointerDown}
              onClick={handleClick}
              onDoubleClick={handleDoubleClick}
              onKeyDown={handleKeyDown}
              tabIndex={0}
              className={`absolute group flex flex-col w-[280px] cursor-grab active:cursor-grabbing focus:outline-none z-30 select-none bg-[#FFF9C4] dark:bg-yellow-900/20 border border-yellow-200 dark:border-yellow-700/50 rounded-lg shadow-xl transition-all duration-200`}
              style={style}
            >
                 <div className="flex items-center justify-between p-3 border-b border-yellow-200/50 dark:border-yellow-700/30">
                    <div className="flex items-center gap-2">
                        <FolderOpen size={18} className="text-yellow-600 dark:text-yellow-400" />
                        <span className="font-bold text-gray-800 dark:text-yellow-100 text-sm truncate max-w-[180px]">{task.title}</span>
                    </div>
                    <span className="text-[10px] font-bold bg-yellow-100 dark:bg-yellow-900/50 text-yellow-800 dark:text-yellow-200 px-1.5 py-0.5 rounded-full">{task.files?.length}</span>
                 </div>

                 <div className="p-2 space-y-1 max-h-[240px] overflow-y-auto custom-scrollbar">
                    {task.files?.map((file, idx) => (
                        <div key={idx} className="flex items-center justify-between p-2 bg-white/50 dark:bg-black/20 rounded hover:bg-white/80 dark:hover:bg-black/40 transition-colors group/file">
                            <div className="flex items-center gap-2 overflow-hidden">
                                <FileText size={14} className="text-gray-500 dark:text-gray-400 shrink-0"/>
                                <span className="text-xs text-gray-700 dark:text-gray-200 truncate">{file.name}</span>
                            </div>
                            <a 
                                href={file.url} 
                                download={file.name}
                                onClick={(e) => e.stopPropagation()}
                                className="opacity-0 group-hover/file:opacity-100 p-1 hover:bg-black/10 dark:hover:bg-white/10 rounded transition-opacity"
                            >
                                <Download size={12} className="text-gray-600 dark:text-gray-300"/>
                            </a>
                        </div>
                    ))}
                 </div>

                 {/* Connection Handles */}
                <div 
                    className="absolute -left-2 top-1/2 -translate-y-1/2 w-4 h-4 bg-white border border-gray-300 rounded-full shadow-sm cursor-crosshair hover:scale-125 transition-transform opacity-0 group-hover:opacity-100 z-20 flex items-center justify-center group/handle"
                    onPointerDown={(e) => { e.stopPropagation(); onConnectStart?.(task.id, e); }}
                    onPointerUp={(e) => { e.stopPropagation(); onConnectEnd?.(task.id); }}
                >
                    <div className="w-1.5 h-1.5 bg-gray-400 rounded-full group-hover/handle:bg-domo-primary transition-colors"></div>
                </div>
                <div 
                    className="absolute -right-2 top-1/2 -translate-y-1/2 w-4 h-4 bg-white border border-gray-300 rounded-full shadow-sm cursor-crosshair hover:scale-125 transition-transform opacity-0 group-hover:opacity-100 z-20 flex items-center justify-center group/handle"
                    onPointerDown={(e) => { e.stopPropagation(); onConnectStart?.(task.id, e); }}
                    onPointerUp={(e) => { e.stopPropagation(); onConnectEnd?.(task.id); }}
                >
                    <div className="w-1.5 h-1.5 bg-gray-400 rounded-full group-hover/handle:bg-domo-primary transition-colors"></div>
                </div>
            </div>
        );
    }

    // COLLAPSED / SINGLE FILE VIEW
    return (
        <div 
          id={`task-${task.id}`}
          draggable
          onDragStart={handleDragStart}
          onPointerDown={onPointerDown}
          onClick={handleClick}
          onDoubleClick={handleDoubleClick}
          onKeyDown={handleKeyDown}
          tabIndex={0}
          className="absolute group flex flex-col items-center w-[100px] cursor-grab active:cursor-grabbing focus:outline-none z-10 select-none"
          style={style}
        >
            <div className={`relative w-16 h-20 bg-white rounded-md shadow-sm flex items-center justify-center transition-transform group-hover:scale-105 ${isSelected ? 'ring-2 ring-domo-highlight ring-offset-2 ring-offset-[#0F111A]' : ''}`}>
                {/* Folded corner effect for single file, or Tab for folder */}
                {isFolder ? (
                    <>
                        <div className="absolute top-[-4px] left-0 w-6 h-2 bg-gray-300 rounded-t-sm"></div>
                        <Folder className="text-yellow-500" size={32} strokeWidth={1.5} fill="#FDE047" fillOpacity={0.4} />
                        <div className="absolute bottom-1 right-1 bg-gray-800 text-white text-[8px] px-1 rounded-full font-bold">
                            {task.files?.length}
                        </div>
                    </>
                ) : (
                    <>
                        <div className="absolute top-0 right-0 w-0 h-0 border-t-[12px] border-t-[#0F111A] border-l-[12px] border-l-transparent opacity-20"></div>
                        <div className="absolute top-0 right-0 w-3 h-3 bg-gray-300 rounded-bl-sm"></div>
                        <FileText className="text-gray-600" size={32} strokeWidth={1.5} />
                        {/* Single File Download Button */}
                        {task.files?.[0] && (
                            <a 
                                href={task.files[0].url} 
                                download={task.files[0].name}
                                onClick={(e) => e.stopPropagation()}
                                className="absolute bottom-1 right-1 p-1 bg-domo-primary text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity hover:bg-domo-primary-hover shadow-sm"
                                title="Download"
                            >
                                <Download size={10} />
                            </a>
                        )}
                    </>
                )}

                {/* Connection Handles */}
                <div 
                    className="absolute -left-2 top-1/2 -translate-y-1/2 w-4 h-4 bg-white border border-gray-300 rounded-full shadow-sm cursor-crosshair hover:scale-125 transition-transform opacity-0 group-hover:opacity-100 z-20 flex items-center justify-center group/handle"
                    onPointerDown={(e) => { e.stopPropagation(); onConnectStart?.(task.id, e); }}
                    onPointerUp={(e) => { e.stopPropagation(); onConnectEnd?.(task.id); }}
                >
                    <div className="w-1.5 h-1.5 bg-gray-400 rounded-full group-hover/handle:bg-domo-primary transition-colors"></div>
                </div>
                <div 
                    className="absolute -right-2 top-1/2 -translate-y-1/2 w-4 h-4 bg-white border border-gray-300 rounded-full shadow-sm cursor-crosshair hover:scale-125 transition-transform opacity-0 group-hover:opacity-100 z-20 flex items-center justify-center group/handle"
                    onPointerDown={(e) => { e.stopPropagation(); onConnectStart?.(task.id, e); }}
                    onPointerUp={(e) => { e.stopPropagation(); onConnectEnd?.(task.id); }}
                >
                    <div className="w-1.5 h-1.5 bg-gray-400 rounded-full group-hover/handle:bg-domo-primary transition-colors"></div>
                </div>
            </div>
            <span className={`mt-2 text-[11px] text-center leading-tight px-1.5 py-0.5 rounded break-all line-clamp-2 max-w-full ${isSelected ? 'bg-domo-highlight text-white' : 'text-gray-200 group-hover:bg-white/10'}`}>
                {task.title}
            </span>
        </div>
    );
  }

  // --- STANDARD CARD RENDER ---
  const isCustomColor = task.color?.startsWith('#');
  const stickyStyle = !isCustomColor && variant === 'sticky' ? getStickyStyle(task.id, task.color) : null;

  let cardClasses = "group rounded-lg cursor-grab active:cursor-grabbing transition-shadow relative backdrop-blur-sm focus:outline-none focus:ring-2 focus:ring-domo-primary focus:ring-offset-2 dark:focus:ring-offset-[#1E212B] ";

  if (variant === 'sticky') {
    if (stickyStyle) {
      cardClasses += `${stickyStyle.bg} ${stickyStyle.text} ${stickyStyle.border} border p-4 shadow-md hover:shadow-xl duration-200 w-[280px] flex flex-col justify-between absolute select-none ${isExpanded ? 'z-30' : 'z-10'}`;
    } else if (isCustomColor) {
      const textColorClass = getContrastColor(task.color || '#ffffff');
      cardClasses += `${textColorClass} border border-gray-200 dark:border-gray-700 p-4 shadow-md hover:shadow-xl duration-200 w-[280px] flex flex-col justify-between absolute select-none ${isExpanded ? 'z-30' : 'z-10'}`;
    }
  } else {
    cardClasses += `${transparent ? 'bg-black/20 hover:bg-black/30 dark:bg-black/20 dark:hover:bg-black/30 bg-white/40 hover:bg-white/50' : 'bg-white dark:bg-[#22272b] hover:bg-gray-50 dark:hover:bg-[#2c333a]'} p-3 mb-2 border border-gray-200 dark:border-transparent hover:border-gray-300 dark:hover:border-gray-500 shadow-sm z-10`;
  }

  if (isSelected) {
      cardClasses += " ring-4 ring-blue-500/50 dark:ring-blue-400/60 z-20 scale-[1.02] ";
  }

  const getStatusLabel = (status: string) => {
    switch(status) {
      case 'inbox': return '수신함';
      case 'todo': return '할 일';
      case 'doing': return '진행 중';
      case 'done': return '완료';
      default: return status;
    }
  };

  const formatTimeDisplay = (timeStr: string) => {
    if (!timeStr) return '';
    const parts = timeStr.split('|');
    if (parts.length > 1) {
        return `${parts[0]} ~ ${parts[1]}`;
    }
    return parts[0];
  };

  return (
    <div 
      id={`task-${task.id}`}
      draggable={variant !== 'sticky'}
      onDragStart={handleDragStart}
      onPointerDown={onPointerDown}
      onClick={handleClick}
      onDoubleClick={handleDoubleClick}
      onKeyDown={handleKeyDown}
      tabIndex={0}
      className={cardClasses}
      style={{
          ...style,
          backgroundColor: (variant === 'sticky' && isCustomColor) ? task.color : undefined
      }}
    >
      {variant === 'sticky' && (
          <div className="absolute -top-3 left-3 bg-white/80 dark:bg-black/40 px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider opacity-70 border border-black/5 shadow-sm backdrop-blur-md text-gray-800 dark:text-gray-100">
              {getStatusLabel(task.status)}
          </div>
      )}

      <div className="flex justify-between items-start">
        <span className={`${variant === 'sticky' ? 'font-bold text-lg leading-tight mt-1' : 'text-gray-800 dark:text-gray-100 text-sm font-medium'}`}>
          {task.title}
        </span>
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
            {/* ATTACH FILE BUTTON */}
            <button 
                onClick={(e) => { e.stopPropagation(); onAttachFile?.(task.id); }}
                className="p-1 hover:bg-black/10 dark:hover:bg-white/10 rounded-full transition-colors"
                title="Attach File"
            >
                <Paperclip size={14} className="text-gray-500 dark:text-gray-300" />
            </button>
            {variant !== 'sticky' ? (
            <button 
                onClick={(e) => { e.stopPropagation(); onMove?.(); }}
                className="text-gray-400 hover:text-gray-600 dark:hover:text-white p-1"
            >
                <ChevronRight size={14} />
            </button>
            ) : (
            <button 
                onClick={(e) => { e.stopPropagation(); }}
                className="p-1 hover:bg-black/10 rounded-full transition-colors"
            >
                <MoreHorizontal size={18} />
            </button>
            )}
        </div>
      </div>

      {variant === 'sticky' && task.description && (
        <div 
          className={`transition-all duration-300 ease-in-out overflow-hidden mt-3 ${isExpanded ? 'max-h-96' : 'max-h-[1.45rem]'}`}
        >
          <p className="text-sm opacity-80 font-medium leading-relaxed">
            {task.description}
          </p>
        </div>
      )}

      <div 
        className={`transition-all duration-300 ease-in-out overflow-hidden
          ${variant === 'sticky' 
             ? (isExpanded ? 'max-h-40 opacity-100 mt-4' : 'max-h-0 opacity-0 mt-0') 
             : 'mt-2' 
          }
        `}
      >
        {task.time && (
          <div className={`text-xs flex items-center gap-1 mb-2 ${variant === 'sticky' ? 'opacity-90 font-semibold' : 'text-domo-highlight'}`}>
            {variant !== 'sticky' && <div className="w-1.5 h-1.5 rounded-full bg-domo-highlight"></div>}
            <Clock size={12} className={variant === 'sticky' ? 'inline-block' : 'hidden'} />
            {formatTimeDisplay(task.time)}
          </div>
        )}

        <div className="flex items-end justify-between">
            <div className="flex flex-wrap gap-1">
              {task.taskType !== undefined && (
                <span className={`px-1.5 py-0.5 rounded text-[10px] font-bold shadow-sm bg-opacity-80 border ${task.taskType === 0 ? 'bg-blue-100 text-blue-800 border-blue-200' : 'bg-orange-100 text-orange-800 border-orange-200'}`}>
                    {task.taskType === 0 ? '일' : '메모'}
                </span>
              )}
              {task.tags && task.tags.length > 0 && task.tags.map(tag => {
                const colorStyle = getStickyStyle(tag.id, tag.color);
                return (
                    <span 
                      key={tag.id} 
                      className={`px-1.5 py-0.5 rounded text-[10px] font-bold border ${colorStyle ? colorStyle.bg : 'bg-gray-100'} ${colorStyle ? colorStyle.text : 'text-gray-800'} ${colorStyle ? colorStyle.border : 'border-gray-200'} shadow-sm bg-opacity-80`}
                    >
                      {tag.name}
                    </span>
                );
              })}
            </div>

          <div className={`flex gap-2 ${variant === 'sticky' ? 'opacity-70 ml-auto' : 'text-gray-400 dark:text-gray-500'}`}>
             {(task.description && variant !== 'sticky') && <AlignLeft size={12} />}
             {task.comments && task.comments.length > 0 && (
                <div className="flex items-center gap-0.5 text-[10px]">
                    {variant === 'sticky' ? (
                      <div className="flex items-center gap-1 bg-white/40 dark:bg-black/20 px-1.5 py-0.5 rounded-full">
                         <span className="font-bold">{task.comments.length}</span>
                      </div>
                    ) : (
                      <div className="w-3 h-3 rounded-full bg-gray-300 dark:bg-gray-600 flex items-center justify-center text-[8px] text-gray-700 dark:text-white">
                          {task.comments.length}
                      </div>
                    )}
                </div>
             )}
          </div>
        </div>
      </div>
      {variant === 'sticky' && (
        <>
            <div 
                className="absolute -left-2 top-1/2 -translate-y-1/2 w-4 h-4 bg-white border border-gray-300 rounded-full shadow-sm cursor-crosshair hover:scale-125 transition-transform z-20 flex items-center justify-center group/handle"
                onPointerDown={(e) => { e.stopPropagation(); onConnectStart?.(task.id, e); }}
                onPointerUp={(e) => { e.stopPropagation(); onConnectEnd?.(task.id); }}
            >
                 <div className="w-1.5 h-1.5 bg-gray-400 rounded-full group-hover/handle:bg-domo-primary transition-colors"></div>
            </div>
            <div 
                className="absolute -right-2 top-1/2 -translate-y-1/2 w-4 h-4 bg-white border border-gray-300 rounded-full shadow-sm cursor-crosshair hover:scale-125 transition-transform z-20 flex items-center justify-center group/handle"
                onPointerDown={(e) => { e.stopPropagation(); onConnectStart?.(task.id, e); }}
                onPointerUp={(e) => { e.stopPropagation(); onConnectEnd?.(task.id); }}
            >
                <div className="w-1.5 h-1.5 bg-gray-400 rounded-full group-hover/handle:bg-domo-primary transition-colors"></div>
            </div>
        </>
      )}
    </div>
  );
};

'use client';

import React, { useState, useEffect } from 'react';
import { Task, Comment, Tag as TagType } from '../../types';
import { STICKY_COLORS, getStickyStyle } from '../../lib/canvasUtils';
import { 
  CreditCard, Palette, X, Briefcase, FileText, StickyNote, AlignLeft, 
  Paperclip, Download, List, Bookmark, Tag, Clock, Plus, CheckSquare, ChevronRight 
} from 'lucide-react';

interface TaskDetailModalProps { 
  task: Task; 
  onClose: () => void; 
  onUpdate: (task: Task) => void; 
  currentUser: string; 
}

export const TaskDetailModal: React.FC<TaskDetailModalProps> = ({ task, onClose, onUpdate, currentUser }) => {
  const [desc, setDesc] = useState(task.description || '');
  const [isEditingDesc, setIsEditingDesc] = useState(false);
  const [commentText, setCommentText] = useState('');
  const [title, setTitle] = useState(task.title);
  const [isAddingTag, setIsAddingTag] = useState(false);
  const [newTagText, setNewTagText] = useState('');
  const [newTagColor, setNewTagColor] = useState('blue');
  const [isEditingDate, setIsEditingDate] = useState(false);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [isSettingType, setIsSettingType] = useState(false);

  useEffect(() => {
     setDesc(task.description || '');
     setTitle(task.title);
  }, [task]);

  useEffect(() => {
    if (task.time) {
        if (task.time.includes('|')) {
            const [s, e] = task.time.split('|');
            setStartDate(s || '');
            setEndDate(e || '');
        } else {
             if (/^\d{4}-\d{2}-\d{2}/.test(task.time)) {
                 setStartDate(task.time.split(' ')[0]);
                 setEndDate('');
             } else {
                 setStartDate('');
                 setEndDate('');
             }
        }
    } else {
        setStartDate('');
        setEndDate('');
    }
  }, [task.time]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (e.key === 'Escape') {
            onClose();
        }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [onClose]);

  const handleSaveDesc = () => {
    onUpdate({ ...task, description: desc });
    setIsEditingDesc(false);
  };

  const handleTitleBlur = () => {
    if (title.trim() !== task.title) {
        onUpdate({ ...task, title: title.trim() || task.title });
    }
  };

  const handleAddComment = () => {
    if (!commentText.trim()) return;
    const newComment: Comment = {
        id: Date.now().toString(),
        user: currentUser,
        text: commentText,
        timestamp: '방금 전'
    };
    onUpdate({ 
        ...task, 
        comments: [newComment, ...(task.comments || [])] 
    });
    setCommentText('');
  };

  const addTag = () => {
    if (!newTagText.trim()) return;
    const newTag: TagType = {
        id: Date.now().toString(),
        name: newTagText.trim(),
        color: newTagColor
    };
    onUpdate({ ...task, tags: [...(task.tags || []), newTag] });
    setNewTagText('');
    setIsAddingTag(false);
  };

  const removeTag = (tagId: string) => {
      onUpdate({ ...task, tags: task.tags?.filter(t => t.id !== tagId) });
  };

  const addChecklist = () => {
    const checklistTemplate = `\n\n### 체크리스트\n- [ ] 할 일 1\n- [ ] 할 일 2`;
    const newDesc = desc + checklistTemplate;
    setDesc(newDesc);
    onUpdate({ ...task, description: newDesc });
    setIsEditingDesc(true); 
  };

  const addMember = () => {
     if (!task.tags?.some(t => t.name === currentUser)) {
        const newTag: TagType = { id: Date.now().toString(), name: currentUser, color: 'orange' };
         onUpdate({ ...task, tags: [...(task.tags || []), newTag] });
     }
  };

  const updateTime = (s: string, e: string) => {
    if (!s && !e) onUpdate({ ...task, time: undefined });
    else if (s && !e) onUpdate({ ...task, time: s });
    else if (!s && e) onUpdate({ ...task, time: e });
    else onUpdate({ ...task, time: `${s}|${e}` });
  };

  const setTaskType = (type: number) => {
      onUpdate({ ...task, taskType: type });
      setIsSettingType(false);
  };

  const getStatusLabel = (status: string) => {
    switch(status) {
      case 'inbox': return '수신함';
      case 'todo': return '할 일';
      case 'doing': return '진행 중';
      case 'done': return '완료';
      default: return status;
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-200" onClick={onClose}>
      <div 
        className="w-full max-w-4xl bg-white dark:bg-[#323940] rounded-xl shadow-2xl max-h-[90vh] overflow-y-auto text-gray-800 dark:text-gray-300 border border-gray-200 dark:border-gray-700/50 custom-scrollbar"
        onClick={e => e.stopPropagation()}
      >
        <div className="p-6 md:p-8">
          <div className="flex justify-between items-start mb-6">
             <div className="flex gap-4 w-full">
                <CreditCard className="mt-1.5 text-gray-500 dark:text-gray-400" size={24} />
                <div className="w-full">
                  <input 
                    className="w-full bg-transparent text-xl font-bold text-gray-900 dark:text-gray-100 mb-1 border-2 border-transparent focus:border-domo-primary rounded px-1 -ml-1 outline-none transition-colors"
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    onBlur={handleTitleBlur}
                    onKeyDown={(e) => e.key === 'Enter' && e.currentTarget.blur()}
                  />
                  <div className="flex items-center gap-2 text-sm text-gray-500 dark:text-gray-400">
                    <span>목록:</span>
                    <span className="px-2 py-0.5 bg-gray-100 dark:bg-[#22272b] rounded underline cursor-pointer hover:text-domo-primary transition-colors">
                      {getStatusLabel(task.status)}
                    </span>
                    <div className="w-[1px] h-3 bg-gray-300 dark:bg-gray-600 mx-1"></div>
                    <div className="flex items-center gap-1.5">
                        {STICKY_COLORS.map(c => (
                            <button
                                key={c.id}
                                onClick={() => onUpdate({ ...task, color: c.id })}
                                className={`w-3.5 h-3.5 rounded-full ${c.dot} border border-black/10 transition-all hover:scale-125 ${task.color === c.id ? 'ring-2 ring-domo-primary ring-offset-1 dark:ring-offset-[#323940]' : ''}`}
                                title={c.id}
                            />
                        ))}
                        <div className="relative group/picker ml-1">
                            <div className={`w-4 h-4 rounded-full border border-gray-300 dark:border-gray-600 flex items-center justify-center overflow-hidden transition-all hover:scale-125 cursor-pointer bg-gradient-to-tr from-pink-500 via-red-500 to-yellow-500 ${task.color?.startsWith('#') ? 'ring-2 ring-domo-primary ring-offset-1 dark:ring-offset-[#323940]' : ''}`}
                            >
                                <Palette size={10} className="text-white drop-shadow-md" />
                            </div>
                            <input 
                                type="color" 
                                className="absolute inset-0 opacity-0 cursor-pointer w-full h-full"
                                value={task.color?.startsWith('#') ? task.color : '#ffffff'}
                                onChange={(e) => onUpdate({ ...task, color: e.target.value })}
                                title="Custom Color"
                            />
                        </div>
                    </div>
                  </div>
                </div>
             </div>
             <button onClick={onClose} className="p-2 hover:bg-gray-100 dark:hover:bg-[#22272b] rounded-full text-gray-500 dark:text-gray-400 hover:text-gray-800 dark:hover:text-white transition-colors">
               <X size={20} />
             </button>
          </div>

          <div className="flex flex-col md:flex-row gap-8">
            <div className="flex-1 space-y-8">
              <div className="block md:hidden mb-4">
                 <div className="grid grid-cols-2 gap-2">
                    <button onClick={() => setIsAddingTag(!isAddingTag)} className="btn-action-mobile">라벨</button>
                    <button onClick={() => setIsEditingDate(!isEditingDate)} className="btn-action-mobile">날짜</button>
                 </div>
              </div>

               <div className="flex flex-wrap gap-2 items-center">
                  {task.taskType !== undefined && (
                      <div className={`flex items-center gap-1 px-3 py-1 rounded text-sm font-bold border cursor-default ${task.taskType === 0 ? 'bg-blue-100 text-blue-800 border-blue-200 dark:bg-blue-900/40 dark:text-blue-200' : task.taskType === 2 ? 'bg-gray-100 text-gray-800 border-gray-200 dark:bg-gray-700/50 dark:text-gray-200' : 'bg-orange-100 text-orange-800 border-orange-200 dark:bg-orange-900/40 dark:text-orange-200'}`}>
                          {task.taskType === 0 ? <Briefcase size={12}/> : task.taskType === 2 ? <FileText size={12}/> : <StickyNote size={12}/>}
                          <span>{task.taskType === 0 ? '일' : task.taskType === 2 ? '파일' : '메모'}</span>
                          <button onClick={() => onUpdate({ ...task, taskType: undefined })} className="ml-1 hover:bg-black/10 rounded-full p-0.5"><X size={12} /></button>
                      </div>
                  )}

                  {task.tags && task.tags.length > 0 && (
                      task.tags.map(tag => {
                          const colorStyle = getStickyStyle(tag.id, tag.color);
                          return (
                              <div key={tag.id} className={`flex items-center gap-1 px-2 py-1 rounded text-xs font-bold border ${colorStyle ? colorStyle.bg : 'bg-gray-100'} ${colorStyle ? colorStyle.text : 'text-gray-800'} ${colorStyle ? colorStyle.border : 'border-gray-200'}`}>
                                  <span>{tag.name}</span>
                                  <button onClick={() => removeTag(tag.id)} className="hover:bg-black/10 rounded-full p-0.5"><X size={10} /></button>
                              </div>
                          );
                      })
                  )}
               </div>

              <div>
