}

.dark {
  /* Apple-style Dark Mode (Deep Blue-Blacks) */
  --bg-primary: #000000;
  --bg-secondary: rgba(28, 28, 30, 0.65);
  --bg-tertiary: rgba(44, 44, 46, 0.4);
  --glass-border: rgba(255, 255, 255, 0.12);

  --text-primary: #f5f5f7;
  --text-secondary: #86868b;
  --text-tertiary: #6e6e73;

  --accent: #0a84ff;
  --accent-glow: rgba(10, 132, 255, 0.3);

  --success: #30d158;
  --warning: #ffd60a;
  --error: #ff453a;

  --shadow-glass: 
    0 4px 6px -1px rgba(0, 0, 0, 0.3),
    inset 0 1px 0 rgba(255, 255, 255, 0.1);

  --shadow-glass-hover:
    0 20px 25px -5px rgba(0, 0, 0, 0.4),
    inset 0 1px 0 rgba(255, 255, 255, 0.15);
}

@theme inline {
  --color-background: var(--bg-primary);
  --color-foreground: var(--text-primary);
  --font-sans: -apple-system, BlinkMacSystemFont, "SF Pro Display", "Segoe UI", Roboto, sans-serif;
}

body {
  background: var(--bg-primary);
  color: var(--text-primary);
  font-family: var(--font-sans);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  overflow: hidden; /* Prevent scroll on body for full app feel */
}

/* Utility Classes for Liquid Glass */
.glass-panel {
  background: var(--bg-secondary);
  backdrop-filter: blur(25px) saturate(180%);
  -webkit-backdrop-filter: blur(25px) saturate(180%);
  border: 1px solid var(--glass-border);
  box-shadow: var(--shadow-glass);
}

.glass-card {
  background: var(--bg-tertiary);
  backdrop-filter: blur(16px) saturate(120%);
  -webkit-backdrop-filter: blur(16px) saturate(120%);
  border: 1px solid var(--glass-border);
  box-shadow: var(--shadow-glass);
  transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);
}

.glass-card:hover {
  transform: translateY(-2px) scale(1.01);
  box-shadow: var(--shadow-glass-hover);
  background: var(--bg-secondary);
  border-color: var(--accent);
}

.liquid-bg-blob {
  position: absolute;
  filter: blur(80px);
  z-index: 0;
  opacity: 0.6;
  animation: float 10s ease-in-out infinite;
}

@keyframes float {
  0% { transform: translate(0px, 0px) scale(1); }
  33% { transform: translate(30px, -50px) scale(1.1); }
  66% { transform: translate(-20px, 20px) scale(0.95); }
  100% { transform: translate(0px, 0px) scale(1); }
}

/* Inputs */
input, textarea {
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid var(--glass-border);
  backdrop-filter: blur(10px);
  color: var(--text-primary);
  transition: all 0.2s ease;
}

input:focus, textarea:focus {
  background: rgba(255, 255, 255, 0.1);
  border-color: var(--accent);
  box-shadow: 0 0 0 4px var(--accent-glow);
  outline: none;
}

/* Buttons */
.btn-primary {
  background: var(--accent);
  color: white;
  box-shadow: 0 4px 12px var(--accent-glow);
  border: 1px solid rgba(255, 255, 255, 0.2);
  transition: all 0.2s ease;
}

.btn-primary:hover {
  transform: translateY(-1px);
  filter: brightness(1.1);
  box-shadow: 0 6px 16px var(--accent-glow);
}

.btn-primary:active {
  transform: translateY(0px);
}

/* Scrollbar */
::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: rgba(128, 128, 128, 0.3);
  border-radius: 10px;
}
::-webkit-scrollbar-thumb:hover {
  background: rgba(128, 128, 128, 0.5);
}

