const App: React.FC = () => {
  const [view, setView] = useState<ViewState>(ViewState.HOME);
  const [activeTrip] = useState<Trip>(MOCK_TRIP);
  const [checkIns, setCheckIns] = useState<CheckInRecord[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [report, setReport] = useState<string>('');
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleCheckIn = async (item: ItineraryItem) => {
    setIsLoading(true);
    try {
      const pos = await getCurrentPosition().catch(() => ({ latitude: 0, longitude: 0 }));

      const distance = calculateDistance(pos, item.coords);
      const isVerified = distance < 500; // 500m radius

      const record: CheckInRecord = {
        id: Date.now().toString(),
        tripId: activeTrip.id,
        timestamp: Date.now(),
        locationName: item.locationName,
        coords: pos,
        type: 'check-in',
        verified: isVerified,
        itineraryItemId: item.id
      };

      setCheckIns(prev => [...prev, record]);
      alert(`Checked in at ${item.locationName}!\nDistance: ${Math.round(distance)}m\nVerified: ${isVerified}`);
    } catch (error) {
      console.error("Check-in failed", error);
      alert("Check-in failed. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleReceiptCapture = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).replace('data:', '').replace(/^.+,/, '');
        try {
            const result = await analyzeReceiptImage(base64String);
            const newExpense: Expense = {
                id: Date.now().toString(),
                tripId: activeTrip.id,
                date: result.date || new Date().toISOString().split('T')[0],
                merchant: result.merchant || 'Unknown Merchant',
                amount: result.amount || 0,
                category: result.category || 'Uncategorized',
                imageUrl: reader.result as string
            };
            setExpenses(prev => [...prev, newExpense]);
        } catch (apiError) {
            console.error(apiError);
            alert("Could not analyze receipt. Please try again.");
        }
      };
      reader.readAsDataURL(file);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleGenerateReport = async () => {
    setIsLoading(true);
    try {
      const reportText = await generateTripReport(checkIns, expenses, 'ja', activeTrip.itinerary);
      setReport(reportText);
    } catch (error) {
      console.error(error);
      alert("Failed to generate report.");
    } finally {
      setIsLoading(false);
    }
  };

