      <div>
        <h3 className="text-lg font-bold text-gray-800 mb-3 px-1">Today's Itinerary</h3>
        <div className="space-y-3">
          {activeTrip.itinerary.map(item => {
            const isCheckedIn = checkIns.some(c => c.itineraryItemId === item.id);
            return (
              <div key={item.id} className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex justify-between items-center">
                <div className="flex-1">
                  <div className="flex items-center text-indigo-600 font-bold mb-1">
                    <span className="text-sm">{item.scheduledTime}</span>
                    <span className="mx-2 text-gray-300">|</span>
                    <span className="text-gray-900">{item.title}</span>
                  </div>
                  <div className="text-xs text-gray-500 flex items-center">
                    <IconMapPin className="w-3 h-3 mr-1" />
