       <div className="space-y-3">
         {expenses.length === 0 ? (
           <div className="text-center py-12 text-gray-400 bg-white rounded-xl border border-dashed border-gray-200">
             <IconReceipt className="w-12 h-12 mx-auto mb-2 opacity-20" />
             <p>No expenses yet</p>
           </div>
         ) : (
           expenses.map(exp => (
             <div key={exp.id} className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex justify-between items-center">
               <div className="flex items-center space-x-3">
                 <div className="w-10 h-10 bg-gray-100 rounded-lg flex items-center justify-center text-xl">
                    🧾
                 </div>
                 <div>
                   <div className="font-bold text-gray-900">{exp.merchant}</div>
                   <div className="text-xs text-gray-500">{exp.date} • {exp.category}</div>
                 </div>
               </div>
               <div className="font-mono font-bold text-gray-800">
                 ¥{exp.amount.toLocaleString()}
               </div>
             </div>
           ))
         )}
       </div>
    </div>
  );

  const renderReport = () => (
    <div className="h-full flex flex-col">
      <div className="flex justify-between items-center mb-4 px-1">
        <h2 className="text-xl font-bold text-gray-800">Trip Report</h2>
        <button 
          onClick={handleGenerateReport}
          disabled={isLoading}
          className="text-indigo-600 font-medium text-sm hover:underline disabled:opacity-50"
        >
          {report ? 'Regenerate' : 'Generate'}
        </button>
      </div>

      <div className="flex-1 bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden flex flex-col">
        {isLoading ? (
          <div className="flex-1 flex items-center justify-center flex-col text-gray-400">
            <div className="w-8 h-8 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin mb-4"></div>
            Generating Report...
          </div>
        ) : report ? (
          <div className="flex-1 overflow-auto p-6 prose prose-sm max-w-none">
            <pre className="whitespace-pre-wrap font-sans text-gray-700">{report}</pre>
          </div>
        ) : (
          <div className="flex-1 flex items-center justify-center flex-col text-gray-400 p-8 text-center">
            <IconFileText className="w-16 h-16 mb-4 opacity-20" />
            <p>Generate a summary report of your trip, including itinerary compliance and expense validation.</p>
          </div>
        )}
      </div>
    </div>
  );

  return (
    <div className="max-w-md mx-auto h-screen bg-gray-50 flex flex-col shadow-2xl overflow-hidden font-sans">
      <div className="flex-1 overflow-y-auto p-4 scrollbar-hide">
        {view === ViewState.HOME && renderHome()}
        {view === ViewState.SCANNER && renderExpenses()}
        {view === ViewState.REPORT && renderReport()}
      </div>

      <nav className="bg-white border-t border-gray-200 px-6 py-3 flex justify-between items-center pb-safe">
        <button 
          onClick={() => setView(ViewState.HOME)}
          className={`flex flex-col items-center space-y-1 ${view === ViewState.HOME ? 'text-indigo-600' : 'text-gray-400'}`}
        >
          <IconHome className="w-6 h-6" />
          <span className="text-[10px] font-medium">Home</span>
        </button>
        <button 
          onClick={() => setView(ViewState.SCANNER)}
          className={`flex flex-col items-center space-y-1 ${view === ViewState.SCANNER ? 'text-indigo-600' : 'text-gray-400'}`}
        >
          <IconReceipt className="w-6 h-6" />
          <span className="text-[10px] font-medium">Expenses</span>
        </button>
        <button 
          onClick={() => setView(ViewState.REPORT)}
          className={`flex flex-col items-center space-y-1 ${view === ViewState.REPORT ? 'text-indigo-600' : 'text-gray-400'}`}
        >
          <IconFileText className="w-6 h-6" />
          <span className="text-[10px] font-medium">Report</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeReceiptImage = async (base64Image: string): Promise<any> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg', // Assuming JPEG for camera captures
              data: base64Image,
            },
          },
          {
            text: "Analyze this Japanese receipt. Extract the merchant name, total amount (number only), date (YYYY-MM-DD), and category (Meals, Transport, Hotel, Other). Return JSON.",
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            merchant: { type: Type.STRING },
            amount: { type: Type.NUMBER },
            date: { type: Type.STRING },
            category: { type: Type.STRING },
          },
        }
      }
    });

    if (response.text) {
      const text = response.text.replace(/```json/g, '').replace(/```/g, '').trim();
      return JSON.parse(text);
    }
    throw new Error("No data returned");
  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    throw error;
  }
};

export const generateTripReport = async (checkIns: any[], expenses: any[], language: 'ja' | 'ko' = 'ja', itinerary: any[] = []): Promise<string> => {
  try {
    const langInstruction = language === 'ja'
      ? "Japanese (with Korean translation in parentheses for key points)"
      : "Korean (with Japanese translation in parentheses for key points)";

    const prompt = `
      Create a professional business trip report in ${langInstruction}.

      Trip Data:
      Planned Itinerary: ${JSON.stringify(itinerary)}
      Actual Check-ins: ${JSON.stringify(checkIns)}
      Expenses: ${JSON.stringify(expenses)}

      Formatting Requirements:
      - Use Markdown.
      - Use '## ' for Section Headers.
      - Use '**' for bolding key numbers, times, and status (e.g., **On Time**, **¥5,000**).
      - Use '- ' for lists.

      Structure:
      ## 1. Summary (概要/개요)
      ## 2. Schedule Verification (日程予実/일정 확인) 
      (Compare planned times vs actual check-in times. Mark as On Time/Late).
      ## 3. Activity Log (活動履歴/활동 내역)
      ## 4. Expense Summary (経費精算/경비 정산)
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Report generation failed.";
  } catch (error) {
    console.error("Report Generation Failed:", error);
    return "Error generating report due to API limits or network issues.";
  }
};
